import{_ as t,o,c as a,a3 as s}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"38C. Caring Responsibilities Casual Employees","description":"","frontmatter":{"title":"38C. Caring Responsibilities Casual Employees","eba":"Mental Health Services 2024-2028","topics":["leave","preliminary"]},"headers":[],"relativePath":"ebas/mental-health/common-terms/leave/38C-caring-responsibilities-casual-employees.md","filePath":"ebas/mental-health/common-terms/leave/38C-caring-responsibilities-casual-employees.md"}'),n={name:"ebas/mental-health/common-terms/leave/38C-caring-responsibilities-casual-employees.md"};function r(i,e,l,p,m,c){return o(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="_38c-caring-responsibilities-casual-employees" tabindex="-1">38C. Caring Responsibilities Casual Employees <a class="header-anchor" href="#_38c-caring-responsibilities-casual-employees" aria-label="Permalink to &quot;38C. Caring Responsibilities Casual Employees&quot;">​</a></h1><p>Note: This clause applies to casual Employees only</p><p><strong>38C.1</strong> Entitlement Subject to the evidentiary and notice requirements that apply to carer’s leave under <a href="/eba/ebas/mental-health/common-terms/leave/38A-personal-leave.html">clause 38A</a>, a casual Employee is entitled to be unavailable to attend work, or to leave work, if they need to provide care or support to a member of the Employee’s immediate family or household because of:</p><p><strong>(a)</strong> a personal illness, or personal injury, affecting them</p><p><strong>(b)</strong> an unexpected emergency affecting them</p><p><strong>(c)</strong> the birth of a child; or</p><p><strong>(d)</strong> after the death of an immediate family or household member.</p><p><strong>38C.2</strong> Period of Leave The Employee is entitled to not be available to attend work for up to two days per occasion on carer&#39;s leave in accordance with the NES, which may be taken as a single continuous period of up to two days or any longer or separate periods to which the Employer and Employee agree.</p><p><strong>38C.3</strong> Evidence and Notice Requirements - Carers Leave</p><p><strong>(a)</strong> Evidence requirements The Employee must, if required by the Employer, establish by production of a Proof of Attendance or statutory declaration or other evidence that would satisfy a reasonable person, that a member of the Employee&#39;s immediate family or household has either:</p><p><strong>(i)</strong> an illness or injury; or</p><p><strong>(ii)</strong> an unexpected emergency; that requires their care or support. In the case of an unexpected emergency, the Employee will identify the nature of the emergency. An &#39;unexpected emergency&#39; includes providing care or support to a member of the Employee’s immediate family or household experiencing family and domestic violence as described at <a href="/eba/ebas/mental-health/common-terms/leave/45-family-and-domestic-violence-leave.html">clause 45</a>(Family and Domestic Violence).</p><p><strong>(b)</strong> Notice requirements</p><p><strong>(i)</strong> The Employee must, where practicable, give the Employer notice of the intention to take leave prior to the absence, that includes: A. the name of the person requiring care or support and their relationship to the Employee, B. the reasons for taking such leave, and C. the estimated length of absence.</p><p><strong>(ii)</strong> If it is not practicable for the Employee to give prior notice of absence, the Employee must notify the Employer of the absence as soon as reasonably practicable.</p><p><strong>(iii)</strong> Notification of absence due to this clause shall be as per procedure at 38A.5(b).</p><p><strong>38C.4</strong> Payment for Leave The casual Employee is not entitled to any payment for the period of non-attendance.</p><p><strong>38C.5</strong> Re-engagement An Employer must not fail to re-engage a casual Employee because the Employee accessed the entitlements provided for in this clause. The rights of the Employer to engage or not engage a casual Employee are otherwise not affected.</p>',18)])])}const u=t(n,[["render",r]]);export{d as __pageData,u as default};
